{action_set_definitions}: {
  "search_ledger": {
    "description": "Searches for transaction records in either the General Ledger (internal) or the Sub-Ledger (bank/external). Use this to find entry IDs and amounts.",
    "parameters": {
      "type": "object",
      "properties": {
        "ledger_type": {
          "type": "string",
          "enum": [
            "general_ledger",
            "sub_ledger"
          ],
          "description": "The specific ledger to query."
        },
        "search_term": {
          "type": "string",
          "description": "The keyword or batch name to search for (e.g., 'Holiday-Main', 'Adyen', 'Amex')."
        }
      },
      "required": [
        "ledger_type",
        "search_term"
      ]
    },
    "example_output": {
      "entries": [
        {
          "id": "GL-9981",
          "description": "Holiday-Main POS Batch",
          "amount": 50000.0,
          "status": "unreconciled"
        }
      ]
    }
  },
  "acquire_record_lock": {
    "description": "Locks a high-value transaction record to prevent concurrent modification during reconciliation, adhering to internal control protocols.",
    "parameters": {
      "type": "object",
      "properties": {
        "entry_id": {
          "type": "string",
          "description": "The unique ID of the ledger entry to lock."
        }
      },
      "required": [
        "entry_id"
      ]
    },
    "example_output": {
      "lock_status": "active",
      "lock_id": "LCK-552"
    }
  },
  "link_transactions": {
    "description": "Pairs internal General Ledger entries with external Sub-Ledger entries to mark them as reconciled.",
    "parameters": {
      "type": "object",
      "properties": {
        "gl_entry_id": {
          "type": "string",
          "description": "The ID of the General Ledger entry."
        },
        "sub_ledger_entry_ids": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "A list of IDs from the sub-ledger (bank deposits) to match against the GL entry."
        }
      },
      "required": [
        "gl_entry_id",
        "sub_ledger_entry_ids"
      ]
    },
    "example_output": {
      "matched_status": "success",
      "matched_pairs_count": 2
    }
  },
  "create_adjustment_entry": {
    "description": "Creates a journal entry to record fees, chargebacks, or resolve variances in the reconciliation log.",
    "parameters": {
      "type": "object",
      "properties": {
        "parent_gl_id": {
          "type": "string",
          "description": "The GL ID this adjustment is associated with."
        },
        "amount": {
          "type": "number",
          "description": "The dollar amount of the adjustment."
        },
        "category": {
          "type": "string",
          "enum": [
            "Merchant Fee",
            "Chargeback",
            "Processing Error"
          ],
          "description": "The nature of the adjustment."
        },
        "description": {
          "type": "string",
          "description": "Detailed explanation for the audit trail."
        }
      },
      "required": [
        "parent_gl_id",
        "amount",
        "category",
        "description"
      ]
    },
    "example_output": {
      "adjustment_id": "ADJ-404",
      "status": "posted"
    }
  },
  "get_reconciliation_summary": {
    "description": "Retrieves the current balance and variance for a specific batch after matches and adjustments.",
    "parameters": {
      "type": "object",
      "properties": {
        "gl_entry_id": {
          "type": "string",
          "description": "The unique ID of the General Ledger entry."
        }
      },
      "required": [
        "gl_entry_id"
      ]
    },
    "example_output": {
      "ledger_balance": 50000.0,
      "matched_subtotal": 48500.0,
      "adjustments_total": 1500.0,
      "variance": 0.0
    }
  }
